const body = $input.first().json.body ?? $input.first().json;

const full_name = body.full_name ?? 'Unknown';
const email = body.email ?? '';
const extracted_cv_text = body.extracted_cv_text ?? '';
const github_username = body.github_username ?? '';

const questions = {};
for (let i = 1; i <= 18; i++) {
  questions[`q${i}`] = Number(body[`q${i}`] ?? 0);
}

async function callWorkflow(path, payload) {
  try {
    const res = await fetch(`http://localhost:5678/webhook/${path}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });

    const raw = await res.text();
    try {
      return JSON.parse(raw);
    } catch (e) {
      return { error: 'parse error', status: res.status, raw };
    }
  } catch (e) {
    return { error: e.message ?? 'request failed' };
  }
}

const [cvResult, pcmResult, githubResult] = await Promise.all([
  callWorkflow('soft-skills-extract', { extracted_cv_text, full_name, email }),
  callWorkflow('pcm-test', { full_name, ...questions }),
  callWorkflow('github-analysis', { github_username })
]);

return [{
  json: {
    full_name,
    email,
    github_username,
    cv: cvResult,
    pcm: pcmResult,
    github: githubResult
  }
}];

const raw = $input.first().json.text
            ?? $input.first().json.response
            ?? $input.first().json.output
            ?? '';

function clampScore(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return 0;
  return Math.max(0, Math.min(100, Math.round(n * 100) / 100));
}

function extractFirstJsonObject(input) {
  const text = String(input || '');
  const start = text.indexOf('{');
  if (start < 0) return '';

  let depth = 0;
  let inString = false;
  let escaped = false;

  for (let i = start; i < text.length; i++) {
    const ch = text[i];

    if (inString) {
      if (escaped) {
        escaped = false;
      } else if (ch === '\\') {
        escaped = true;
      } else if (ch === '"') {
        inString = false;
      }
      continue;
    }

    if (ch === '"') {
      inString = true;
      continue;
    }

    if (ch === '{') depth++;
    if (ch === '}') depth--;

    if (depth === 0) {
      return text.slice(start, i + 1);
    }
  }

  return text.slice(start);
}

function tryParseJson(input) {
  const cleaned = String(input || '')
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .replace(/[\u201C\u201D]/g, '"')
    .trim();

  const candidate = extractFirstJsonObject(cleaned) || cleaned;
  const withoutTrailingCommas = candidate.replace(/,\s*([}\]])/g, '$1');

  try {
    return JSON.parse(withoutTrailingCommas);
  } catch (e) {
    return null;
  }
}

let parsed = tryParseJson(raw);

// Never throw here: return a safe object so backend can persist and UI can render.
if (!parsed || typeof parsed !== 'object') {
  parsed = {
    overall_score: 0,
    personality_type: 'Analyseur',
    skills: [],
    merged_soft_skills: {
      communication: 0,
      leadership: 0,
      teamwork: 0,
      adaptability: 0,
      problem_solving: 0
    },
    source_data: {
      cv_score: 0,
      pcm_score: 0,
      github_score: 0
    },
    summary: '',
    key_strengths: [],
    training_recommendations: 'LLM response was not valid JSON; using safe fallback.',
    parse_error: true,
    raw_excerpt: String(raw).substring(0, 300)
  };
}

parsed.overall_score = clampScore(parsed.overall_score ?? parsed.overallScore ?? 0);
parsed.personality_type = parsed.personality_type ?? parsed.personalityType ?? 'Analyseur';
parsed.skills = Array.isArray(parsed.skills) ? parsed.skills : [];
parsed.summary = String(parsed.summary ?? '');

parsed.merged_soft_skills = parsed.merged_soft_skills ?? parsed.mergedSoftSkills ?? {};
parsed.merged_soft_skills.communication = clampScore(parsed.merged_soft_skills.communication ?? 0);
parsed.merged_soft_skills.leadership = clampScore(parsed.merged_soft_skills.leadership ?? 0);
parsed.merged_soft_skills.teamwork = clampScore(parsed.merged_soft_skills.teamwork ?? 0);
parsed.merged_soft_skills.adaptability = clampScore(parsed.merged_soft_skills.adaptability ?? 0);
parsed.merged_soft_skills.problem_solving = clampScore(parsed.merged_soft_skills.problem_solving ?? 0);

parsed.source_data = parsed.source_data ?? parsed.sourceData ?? {};
parsed.source_data.cv_score = clampScore(parsed.source_data.cv_score ?? 0);
parsed.source_data.pcm_score = clampScore(parsed.source_data.pcm_score ?? 0);
parsed.source_data.github_score = clampScore(parsed.source_data.github_score ?? 0);

parsed.key_strengths = Array.isArray(parsed.key_strengths) ? parsed.key_strengths : [];
parsed.training_recommendations = parsed.training_recommendations ?? '';

return [{ json: parsed }];
